const verseList=['JER.29.11','PSA.23.1','PRO.3.5-6','PHP.4.13','ISA.40.31','MAT.11.28','JHN.3.16','ROM.8.28','1CO.13.13','PSA.46.1','JOS.1.9','HEB.11.1','ROM.12.2','2CO.5.7','GAL.5.22-23','EPH.2.8-9','PHP.4.6-7','COL.3.23','1JN.4.19','PSA.119.105','PSA.91.1-2','MAT.6.33','ISA.41.10','ROM.15.13','PSA.37.4','PRO.16.3','MAT.5.16','2TI.1.7','PSA.27.1','HEB.13.8'];const CACHE_KEY='bible_verse_cache';function getVerseCache(){try{var raw=localStorage.getItem(CACHE_KEY);if(!raw)return{};return JSON.parse(raw);}catch(e){return{};}}
