/* ─── Wallpaper generator ────────────────────────────────────────────
   Composites the daily verse over a CC-licensed Unsplash photo (via the
   get-unsplash-photo Netlify function) at phone/tablet/laptop resolutions.
   Falls back to an elegant gradient when no Unsplash key is configured or
   a photo can't load, so the feature always works. */
(function () {
  var WP_DEVICES = {
    phone:  { w: 1170, h: 2532, orientation: 'portrait' },
    tablet: { w: 1668, h: 2388, orientation: 'portrait' },
    laptop: { w: 2560, h: 1600, orientation: 'landscape' }
  };
  var wp = { device: 'phone', mood: 'verse', meta: {}, imgCache: {}, fontsReady: false };

  // Per-verse Unsplash themes so the photo matches the passage
  // (keyed by the same verse ids as verseList).
  var WP_THEMES = {
    'JER.29.11': 'sunrise horizon hope',       'PSA.23.1': 'green pasture meadow sheep',
    'PRO.3.5-6': 'forest path trail',          'PHP.4.13': 'mountain summit climber',
    'ISA.40.31': 'eagle soaring sky',          'MAT.11.28': 'calm lake still water',
    'JHN.3.16': 'starry night sky earth',      'ROM.8.28': 'golden field sunlight',
    '1CO.13.13': 'warm sunset soft glow',      'PSA.46.1': 'mountain rock fortress',
    'JOS.1.9': 'cliff sunrise courage',        'HEB.11.1': 'misty forest fog',
    'ROM.12.2': 'spring blossom new growth',   '2CO.5.7': 'foggy road morning mist',
    'GAL.5.22-23': 'orchard garden fruit',     'EPH.2.8-9': 'light rays through clouds',
    'PHP.4.6-7': 'peaceful calm ocean',        'COL.3.23': 'wheat harvest golden field',
    '1JN.4.19': 'warm sunrise glow',           'PSA.119.105': 'lantern path night light',
    'PSA.91.1-2': 'starry mountain night shelter', 'MAT.6.33': 'sunbeam forest morning',
    'ISA.41.10': 'lighthouse sea storm',       'ROM.15.13': 'blooming flowers spring',
    'PSA.37.4': 'wildflower meadow sunshine',  'PRO.16.3': 'open road horizon',
    'MAT.5.16': 'sunlight through trees',      '2TI.1.7': 'bold mountain peak dawn',
    'PSA.27.1': 'dawn light valley',           'HEB.13.8': 'ancient rocks timeless desert'
  };
  var WP_MOODS = {
    calm: 'calm still water minimal',
    nature: 'nature landscape forest',
    sky: 'sky clouds stars',
    light: 'golden hour sunlight rays',
    mountains: 'mountains alpine peaks'
  };
  var WP_DEFAULT_QUERY = 'landscape,nature,minimal,sky';

  function currentQuery() {
    if (wp.mood !== 'verse') return WP_MOODS[wp.mood] || WP_DEFAULT_QUERY;
    try {
      var id = getVerseForDate(viewingDate || new Date());
      return WP_THEMES[id] || WP_DEFAULT_QUERY;
    } catch (e) { return WP_DEFAULT_QUERY; }
  }

  var overlay, canvasEl, loadingEl, creditEl;

  function $(id) { return document.getElementById(id); }
  function toast(m) { if (typeof showToast === 'function') showToast(m); }

  // ─── Photo fetch + image loading ───
  function photoUrl(base, w, h) {
    var sep = base.indexOf('?') >= 0 ? '&' : '?';
    return base + sep + 'w=' + w + '&h=' + h + '&fit=crop&crop=entropy&q=80&fm=jpg';
  }
  function loadImage(url) {
    return new Promise(function (res, rej) {
      var img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = function () { res(img); };
      img.onerror = function () { rej(new Error('img')); };
      img.src = url;
    });
  }
  function metaKey(orientation, query) { return orientation + '|' + query; }
  async function ensureMeta(orientation, query) {
    var key = metaKey(orientation, query);
    if (wp.meta[key]) return wp.meta[key];
    var reason = 'error';
    try {
      var r = await fetch('/.netlify/functions/get-unsplash-photo?action=random&orientation=' + orientation
        + '&query=' + encodeURIComponent(query));
      var data = await r.json();
      if (data && data.imageBaseUrl && !data.error && !data.noKey) {
        wp.meta[key] = data;
        return data;
      }
      if (data && data.noKey) reason = 'nokey';
    } catch (e) { /* fall through to gradient */ }
    wp.meta[key] = { gradient: true, id: 'grad-' + key, reason: reason };
    return wp.meta[key];
  }
  async function ensureImage(device, meta) {
    if (meta.gradient) return null;
    var cache = wp.imgCache[device];
    if (cache && cache.id === meta.id) return cache.img;
    var d = WP_DEVICES[device];
    try {
      var img = await loadImage(photoUrl(meta.imageBaseUrl, d.w, d.h));
      wp.imgCache[device] = { id: meta.id, img: img };
      return img;
    } catch (e) {
      meta.gradient = true; // photo failed to load (often CORS) → gradient
      meta.reason = 'imgfail';
      return null;
    }
  }

  // ─── Canvas drawing ───
  function coverDraw(ctx, img, W, H) {
    var ir = img.width / img.height, cr = W / H, sw, sh, sx, sy;
    if (ir > cr) { sh = img.height; sw = sh * cr; sx = (img.width - sw) / 2; sy = 0; }
    else { sw = img.width; sh = sw / cr; sx = 0; sy = (img.height - sh) / 2; }
    ctx.drawImage(img, sx, sy, sw, sh, 0, 0, W, H);
  }
  function gradientBg(ctx, W, H) {
    // Warm tonal gradient (matches the app palette) — clearly not black, and
    // dark enough for white text to stay legible.
    var g = ctx.createLinearGradient(0, 0, W, H);
    g.addColorStop(0, '#6f6250');
    g.addColorStop(0.55, '#4a4036');
    g.addColorStop(1, '#2f2822');
    ctx.fillStyle = g; ctx.fillRect(0, 0, W, H);
    // Gentle vignette for depth.
    var r = ctx.createRadialGradient(W / 2, H / 2, Math.min(W, H) * 0.1, W / 2, H / 2, Math.max(W, H) * 0.75);
    r.addColorStop(0, 'rgba(0,0,0,0)');
    r.addColorStop(1, 'rgba(0,0,0,.26)');
    ctx.fillStyle = r; ctx.fillRect(0, 0, W, H);
  }
  function scrim(ctx, W, H) {
    var g = ctx.createLinearGradient(0, 0, 0, H);
    g.addColorStop(0, 'rgba(0,0,0,.30)');
    g.addColorStop(0.5, 'rgba(0,0,0,.45)');
    g.addColorStop(1, 'rgba(0,0,0,.38)');
    ctx.fillStyle = g; ctx.fillRect(0, 0, W, H);
  }
  function wrap(ctx, text, maxW, cjk) {
    var lines = [], line = '', i, t;
    if (cjk) {
      for (i = 0; i < text.length; i++) {
        t = line + text[i];
        if (ctx.measureText(t).width > maxW && line) { lines.push(line); line = text[i]; }
        else line = t;
      }
    } else {
      var words = text.split(' ');
      for (i = 0; i < words.length; i++) {
        t = line ? line + ' ' + words[i] : words[i];
        if (ctx.measureText(t).width > maxW && line) { lines.push(line); line = words[i]; }
        else line = t;
      }
    }
    if (line) lines.push(line);
    return lines;
  }
  function draw(device, meta, img, verse) {
    var d = WP_DEVICES[device], W = d.w, H = d.h, min = Math.min(W, H);
    canvasEl.width = W; canvasEl.height = H;
    var ctx = canvasEl.getContext('2d');

    if (img) { coverDraw(ctx, img, W, H); scrim(ctx, W, H); }
    else gradientBg(ctx, W, H);

    var enSize = Math.round(min * 0.045), zhSize = Math.round(min * 0.043), refSize = Math.round(min * 0.026);
    var gap = Math.round(min * 0.02), maxW = Math.min(W * 0.82, min * 1.15);
    var enFont = '600 ' + enSize + 'px Georgia, "Times New Roman", serif';
    var zhFont = '500 ' + zhSize + 'px "Noto Serif TC", "Songti TC", serif';
    var refFont = refSize + 'px Georgia, serif';
    var enLH = enSize * 1.42, zhLH = zhSize * 1.62, refLH = refSize * 1.6;

    ctx.textAlign = 'center'; ctx.textBaseline = 'top';
    ctx.font = enFont; var enLines = wrap(ctx, '“' + verse.english.quote + '”', maxW, false);
    ctx.font = zhFont; var zhLines = wrap(ctx, '「' + verse.chinese.quote + '」', maxW, true);

    var items = [];
    enLines.forEach(function (l) { items.push({ t: l, font: enFont, lh: enLH, a: 1 }); });
    items.push({ gap: gap * 0.5 });
    items.push({ t: '— ' + verse.english.reference, font: refFont, lh: refLH, a: 0.85 });
    items.push({ gap: gap * 1.1, divider: true });
    zhLines.forEach(function (l) { items.push({ t: l, font: zhFont, lh: zhLH, a: 1 }); });
    items.push({ gap: gap * 0.5 });
    items.push({ t: '— ' + verse.chinese.reference, font: refFont, lh: refLH, a: 0.85 });

    var blockH = items.reduce(function (s, it) { return s + (it.lh || it.gap || 0); }, 0);
    var y = (H - blockH) / 2;

    ctx.shadowColor = 'rgba(0,0,0,.55)'; ctx.shadowBlur = min * 0.012; ctx.shadowOffsetY = 2;
    items.forEach(function (it) {
      if (it.divider) {
        ctx.save(); ctx.shadowColor = 'transparent';
        ctx.strokeStyle = 'rgba(255,255,255,.5)'; ctx.lineWidth = Math.max(1, min * 0.0015);
        ctx.beginPath(); ctx.moveTo(W / 2 - min * 0.05, y + it.gap / 2); ctx.lineTo(W / 2 + min * 0.05, y + it.gap / 2); ctx.stroke();
        ctx.restore();
      }
      if (it.gap) { y += it.gap; return; }
      ctx.font = it.font; ctx.fillStyle = 'rgba(255,255,255,' + it.a + ')';
      ctx.fillText(it.t, W / 2, y); y += it.lh;
    });
    ctx.shadowColor = 'transparent';

    // Watermark + photo credit baked in (UI shows the linked attribution).
    ctx.textAlign = 'center'; ctx.font = Math.round(min * 0.02) + 'px Georgia, serif';
    ctx.fillStyle = 'rgba(255,255,255,.82)';
    ctx.fillText('每日聖經金句 ✦ Daily Bible Quote', W / 2, H - min * 0.07);
    if (meta && meta.photographer && !meta.gradient) {
      ctx.textAlign = 'left'; ctx.font = Math.round(min * 0.016) + 'px Georgia, serif';
      ctx.fillStyle = 'rgba(255,255,255,.68)';
      ctx.fillText('Photo: ' + meta.photographer.name + ' / Unsplash', min * 0.05, H - min * 0.038);
    }
  }

  var WP_REASON = {
    nokey: '漸層底圖（未設定 UNSPLASH_ACCESS_KEY）',
    imgfail: '漸層底圖（照片載入失敗，可能是 CORS）',
    error: '漸層底圖（Unsplash 暫時無法使用）'
  };
  function updateCredit(meta) {
    if (meta && meta.photographer && !meta.gradient) {
      creditEl.innerHTML = 'Photo by <a href="' + meta.photographer.link + '" target="_blank" rel="noopener">'
        + meta.photographer.name + '</a> on <a href="' + meta.photoLink + '" target="_blank" rel="noopener">Unsplash</a>';
    } else {
      creditEl.textContent = WP_REASON[(meta && meta.reason)] || WP_REASON.error;
    }
  }

  var rendering = false;
  async function render() {
    if (rendering || !currentVerse) return;
    rendering = true;
    loadingEl.classList.add('show');
    try {
      var d = WP_DEVICES[wp.device];
      var meta = await ensureMeta(d.orientation, currentQuery());
      var img = await ensureImage(wp.device, meta);
      draw(wp.device, meta, img, currentVerse);
      updateCredit(meta);
    } catch (e) { /* keep last frame */ }
    loadingEl.classList.remove('show');
    rendering = false;
  }

  function currentMeta() { return wp.meta[metaKey(WP_DEVICES[wp.device].orientation, currentQuery())]; }

  function triggerUnsplashDownload() {
    var meta = currentMeta();
    if (meta && meta.id && !meta.gradient) {
      fetch('/.netlify/functions/get-unsplash-photo?action=download&id=' + encodeURIComponent(meta.id)).catch(function () {});
    }
  }

  function exportBlob(cb) {
    try { canvasEl.toBlob(function (b) { cb(b); }, 'image/png'); }
    catch (e) { cb(null); }
  }
  function download() {
    exportBlob(function (blob) {
      if (!blob) { toast('匯出失敗'); return; }
      var a = document.createElement('a');
      a.download = 'daily-bible-wallpaper-' + wp.device + '.png';
      a.href = URL.createObjectURL(blob); a.click(); URL.revokeObjectURL(a.href);
      toast('桌布已下載 ✓');
      triggerUnsplashDownload();
    });
  }
  function share() {
    exportBlob(async function (blob) {
      if (!blob) { toast('分享失敗'); return; }
      var file = new File([blob], 'daily-bible-wallpaper.png', { type: 'image/png' });
      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        try { await navigator.share({ files: [file], title: 'Daily Bible Wallpaper' }); triggerUnsplashDownload(); }
        catch (e) { if (e.name !== 'AbortError') download(); }
      } else { download(); }
    });
  }

  async function open() {
    if (!currentVerse) { toast('經文尚未載入'); return; }
    overlay.classList.add('show'); overlay.setAttribute('aria-hidden', 'false');
    if (!wp.fontsReady && document.fonts && document.fonts.ready) {
      try { await document.fonts.ready; } catch (e) {}
      wp.fontsReady = true;
    }
    render();
  }
  function close() { overlay.classList.remove('show'); overlay.setAttribute('aria-hidden', 'true'); }

  function init() {
    var btn = $('wallpaperButton');
    if (!btn) return;
    overlay = $('wpOverlay'); canvasEl = $('wpCanvas'); loadingEl = $('wpLoading'); creditEl = $('wpCredit');

    btn.addEventListener('click', function (e) {
      e.stopPropagation();
      var fs = $('fontSelector'); if (fs) fs.classList.remove('show');
      var sm = $('shareMenu'); if (sm) sm.classList.remove('show');
      var cp = $('calendarPanel'); if (cp) cp.classList.remove('show');
      open();
    });
    $('wpClose').addEventListener('click', close);
    overlay.addEventListener('click', function (e) { if (e.target === overlay) close(); });
    document.addEventListener('keydown', function (e) { if (e.key === 'Escape' && overlay.classList.contains('show')) close(); });

    $('wpDevices').addEventListener('click', function (e) {
      var b = e.target.closest('.wp-device'); if (!b) return;
      wp.device = b.dataset.device;
      Array.prototype.forEach.call(this.querySelectorAll('.wp-device'), function (el) {
        el.classList.toggle('active', el === b);
      });
      render();
    });
    $('wpMoods').addEventListener('click', function (e) {
      var b = e.target.closest('.wp-mood'); if (!b) return;
      wp.mood = b.dataset.mood;
      Array.prototype.forEach.call(this.querySelectorAll('.wp-mood'), function (el) {
        el.classList.toggle('active', el === b);
      });
      render();
    });
    $('wpShuffle').addEventListener('click', function () {
      var o = WP_DEVICES[wp.device].orientation;
      delete wp.meta[metaKey(o, currentQuery())];
      Object.keys(WP_DEVICES).forEach(function (k) { if (WP_DEVICES[k].orientation === o) delete wp.imgCache[k]; });
      render();
    });
    $('wpDownload').addEventListener('click', download);
    $('wpShare').addEventListener('click', share);
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();
})();
